// Output represents the output of the command
type Output struct {
	Commands []string `json:"commands"`
}

// ToJSON marshals the Output struct to JSON bytes.
func (o *Output) ToJSON() []byte {
	b, err := json.Marshal(o)
	if err != nil {
		log.Fatal(err)
	}
	return b
}

func main() {
	// Example command output
	output := &Output{
		Commands: []string{
			"echo Command1",
			"echo Command2",
		},
	}

	var buf bytes.Buffer
	buf.Write(output.ToJSON())

	// Print the JSON output surrounded by the marker
	fmt.Println("---SAFE---")
	fmt.Println(buf.String())
}
